      "name": "Way of the Sun Soul",
      "classId": "monk",
      "tags": [
        "class:monk",
        "has:features",
        "kind:subclass",
        "subclass:monk--way-of-the-sun-soul"
      ],
      "nameFolded": "way of the sun soul",
      "summary": "Monks of the Way of the Sun Soul learn to channel their own life energy into searing bolts of light. They teach that meditation can unlock the ability to unleash the indomitable light shed by the soul of every living creature.",
